  <script>
    const KANJI = <?= $kanjiJson ?>;
    const groups = ['Semua', ...Array.from(new Set(KANJI.map(item => item.filterGroup)))];
    let activeGroup = 'Semua';
    let query = '';
    let activeItem = KANJI[0];
    let writer = null;

    const $ = (selector) => document.querySelector(selector);
    const grid = $('#kanjiGrid');
    const empty = $('#emptyState');
    const searchInput = $('#searchInput');
    const modal = $('#modal');
    const strokeImg = $('#strokeImg');
    const writerFallback = $('#writerFallback');

    function normalize(value){ return String(value || '').toLowerCase().trim(); }
    function romanReading(text){
      const map = {'にち':'nichi','じつ':'jitsu','ひ':'hi','いち':'ichi','いつ':'itsu','ひと':'hito','こく':'koku','くに':'kuni','じん':'jin','にん':'nin','とし':'toshi','ねん':'nen','だい':'dai','たい':'tai','おお':'oo','じゅう':'juu','に':'ni','ふた':'futa','ほん':'hon','もと':'moto','ちゅう':'chuu','なか':'naka','ちょう':'chou','なが':'naga','しゅつ':'shutsu','で':'de','さん':'san','みっ':'mittsu','じ':'ji','とき':'toki','こう':'kou','ぎょう':'gyou','いく':'iku','けん':'ken','みる':'miru','げつ':'getsu','がつ':'gatsu','つき':'tsuki','ぶん':'bun','ふん':'fun','わかる':'wakaru','ご':'go','あと':'ato','うしろ':'ushiro','まえ':'mae','せい':'sei','しょう':'shou','がく':'gaku','まなぶ':'manabu','えん':'en','こ':'ko','そと':'soto','はち':'hachi','やっ':'yattsu','ろく':'roku','むっ':'muttsu','らい':'rai','くる':'kuru','き':'ki','ちいさい':'chiisai','しち':'shichi','なな':'nana','やま':'yama','わ':'wa','はなす':'hanasu','おんな':'onna','きた':'kita','ひゃく':'hyaku','かく':'kaku','さき':'saki','な':'na','かわ':'kawa','せん':'sen','みず':'mizu','はん':'han','おとこ':'otoko','にし':'nishi','でん':'den','ご':'go','つち':'tsuchi','きく':'kiku','たべる':'taberu','くるま':'kuruma','なに':'nani','なん':'nan','みなみ':'minami','まん':'man','まい':'mai','しろ':'shiro','てん':'ten','はは':'haha','か':'ka','みぎ':'migi','よむ':'yomu','とも':'tomo','ひだり':'hidari','やすむ':'yasumu','ちち':'chichi','あめ':'ame'};
      let out = normalize(text);
      Object.keys(map).forEach(k => { out += ' ' + (text.includes(k) ? map[k] : ''); });
      return out;
    }
    function searchable(item){
      const examples = item.examples.map(ex => `${ex.w} ${ex.r} ${ex.m} ${romanReading(ex.r)}`).join(' ');
      return normalize(`${item.k} ${item.meaning} ${item.group} ${item.on} ${item.kun} ${item.usage} ${examples} ${romanReading(item.kun)} ${romanReading(item.on)}`);
    }
    function filtered(){
      return KANJI.filter(item => {
        const groupOk = activeGroup === 'Semua' || item.filterGroup === activeGroup;
        const queryOk = !query || searchable(item).includes(query);
        return groupOk && queryOk;
      });
    }
    function renderFilters(){
      $('#filters').innerHTML = groups.map(group => `<button class="filter ${group === activeGroup ? 'active' : ''}" data-group="${group}">${group}</button>`).join('');
      document.querySelectorAll('[data-group]').forEach(btn => btn.addEventListener('click', () => { activeGroup = btn.dataset.group; render(); }));
    }
    function render(){
      renderFilters();
      const data = filtered();
      grid.innerHTML = data.map((item, index) => `<button class="card" data-index="${KANJI.indexOf(item)}" style="transition-delay:${(index % 8) * 18}ms"><div class="k jp">${item.k}</div><div class="m">${item.meaning}</div><div class="meta"><span>${item.group}</span><span>${item.strokes} goresan</span></div></button>`).join('');
      empty.classList.toggle('show', data.length === 0);
      document.querySelectorAll('.card').forEach(card => card.addEventListener('click', () => openModal(KANJI[Number(card.dataset.index)])));
      $('#totalCount').textContent = KANJI.length;
    }
    function animationUrl(kanji){ return `https://commons.wikimedia.org/wiki/Special:Redirect/file/${encodeURIComponent(kanji)}-order.gif`; }

    let SVG_DATA = {};
    fetch('data/kanji_strokes_n5.json').then(r=>r.json()).then(d=>{SVG_DATA=d;}).catch(e=>console.error('Failed loading SVG data',e));

    let svgAnimTimer = null;
    let svgCurrentStroke = 0;
    let svgIsPlaying = false;
    let svgSpeed = 1;
    let svgStrokesData = [];

    function calculateLength(pathData) {
        const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        path.setAttribute('d', pathData);
        return path.getTotalLength();
    }

    function initSvgPlayer(item) {
        const svg = document.getElementById('kanjiSvgPlayer');
        const fallbackWriter = document.getElementById('writerFallback');
        const fallbackImg = document.getElementById('strokeImg');
        const strokeCounter = document.getElementById('strokeCounter');

        svg.innerHTML = '';
        clearInterval(svgAnimTimer);
        svgIsPlaying = false;

        const paths = SVG_DATA[item.k];
        if (!paths || paths.length === 0) {
            svg.hidden = true;
            strokeCounter.hidden = true;
            document.getElementById('playPauseBtn').hidden = true;
            document.getElementById('stepBtn').hidden = true;
            document.getElementById('speedBtn').hidden = true;
            // Fallback to GIF or HanziWriter
            fallbackWriter.hidden = true;
            fallbackImg.hidden = false;
            fallbackImg.onerror = () => showFallbackWriter(item);
            fallbackImg.src = animationUrl(item.k) + '?v=' + Date.now();
            return;
        }

        svg.hidden = false;
        fallbackWriter.hidden = true;
        fallbackImg.hidden = true;
        strokeCounter.hidden = false;
        document.getElementById('playPauseBtn').hidden = false;
        document.getElementById('stepBtn').hidden = false;
        document.getElementById('speedBtn').hidden = false;
        document.getElementById('playPauseBtn').textContent = '⏸ Pause';

        svgStrokesData = paths.map((d, i) => {
            const length = calculateLength(d);
            return { d, length, index: i+1 };
        });

        // Add defs for clip paths
        let defs = '<defs>';
        svgStrokesData.forEach((s) => {
             // In KanjiVG, strokes are paths. We can just draw them with dasharray.
             // Wait, the prompt says:
             // <path style="opacity: 0; stroke-dashoffset: 0px;" clip-path="url(...)" d="..." stroke="rgba(170,170,255,1)" stroke-width="200" fill="none" stroke-linecap="round" stroke-linejoin="miter" stroke-dasharray="...">
             // Note: KanjiVG paths are actual stroke outlines if we don't clip, or are they central paths?
             // Actually, KanjiVG provides <path> which ARE the strokes (drawn with stroke-width:3 or similar).
             // Let's adapt the prompt's template. The prompt assumes stroke-width="200", which means it's a mask over something?
             // Wait, if it's KanjiVG, the paths are just d="M...". Let's draw them with stroke="rgba(170,170,255,1)" and stroke-width="3".
        });
        // Let's implement the standard draw:

        // Background guides (grey)
        svgStrokesData.forEach(s => {
            const bgPath = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            bgPath.setAttribute('d', s.d);
            bgPath.setAttribute('stroke', 'rgba(255,255,255,0.1)');
            bgPath.setAttribute('stroke-width', '3');
            bgPath.setAttribute('fill', 'none');
            bgPath.setAttribute('stroke-linecap', 'round');
            bgPath.setAttribute('stroke-linejoin', 'round');
            svg.appendChild(bgPath);
        });

        // Foreground animated paths
        svgStrokesData.forEach(s => {
            const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            path.setAttribute('id', 'strokePath_' + s.index);
            path.setAttribute('d', s.d);
            path.setAttribute('stroke', 'rgba(170,170,255,1)');
            path.setAttribute('stroke-width', '4');
            path.setAttribute('fill', 'none');
            path.setAttribute('stroke-linecap', 'round');
            path.setAttribute('stroke-linejoin', 'round');
            path.setAttribute('stroke-dasharray', s.length + 5);
            path.setAttribute('stroke-dashoffset', s.length + 5);
            path.style.opacity = '0';
            path.style.transition = 'none';
            svg.appendChild(path);
        });

        svgCurrentStroke = 0;
        strokeCounter.textContent = `Stroke: 0 / ${svgStrokesData.length}`;

        // Start animation loop
        svgIsPlaying = true;
        animateNextStroke();
    }

    function resetSvgPaths() {
        svgStrokesData.forEach(s => {
            const p = document.getElementById('strokePath_' + s.index);
            if(p) {
                p.style.transition = 'none';
                p.setAttribute('stroke-dashoffset', s.length + 5);
                p.style.opacity = '0';
            }
        });
        svgCurrentStroke = 0;
        document.getElementById('strokeCounter').textContent = `Stroke: 0 / ${svgStrokesData.length}`;
    }

    function animateNextStroke() {
        if (!svgIsPlaying) return;
        if (svgCurrentStroke >= svgStrokesData.length) {
            svgIsPlaying = false;
            document.getElementById('playPauseBtn').textContent = '▶ Play';
            return;
        }

        const s = svgStrokesData[svgCurrentStroke];
        const p = document.getElementById('strokePath_' + s.index);

        p.style.opacity = '1';
        // Base duration = 600ms, adjust by length
        const dur = (400 + (s.length * 5)) / svgSpeed;

        // Force reflow
        p.getBoundingClientRect();

        p.style.transition = `stroke-dashoffset ${dur}ms ease-out`;
        p.setAttribute('stroke-dashoffset', '0');

        svgCurrentStroke++;
        document.getElementById('strokeCounter').textContent = `Stroke: ${svgCurrentStroke} / ${svgStrokesData.length}`;

        svgAnimTimer = setTimeout(() => {
            animateNextStroke();
        }, dur + 100);
    }

    function togglePlayPause() {
        if (svgCurrentStroke >= svgStrokesData.length) {
            resetSvgPaths();
            svgIsPlaying = true;
            document.getElementById('playPauseBtn').textContent = '⏸ Pause';
            animateNextStroke();
            return;
        }
        svgIsPlaying = !svgIsPlaying;
        document.getElementById('playPauseBtn').textContent = svgIsPlaying ? '⏸ Pause' : '▶ Play';
        if (svgIsPlaying) animateNextStroke();
        else clearTimeout(svgAnimTimer);
    }

    function stepStroke() {
        clearTimeout(svgAnimTimer);
        svgIsPlaying = false;
        document.getElementById('playPauseBtn').textContent = '▶ Play';

        if (svgCurrentStroke >= svgStrokesData.length) {
            resetSvgPaths();
        }

        const s = svgStrokesData[svgCurrentStroke];
        const p = document.getElementById('strokePath_' + s.index);
        p.style.transition = 'none';
        p.style.opacity = '1';
        p.setAttribute('stroke-dashoffset', '0');

        svgCurrentStroke++;
        document.getElementById('strokeCounter').textContent = `Stroke: ${svgCurrentStroke} / ${svgStrokesData.length}`;
    }

    function changeSpeed() {
        const speeds = [0.5, 1, 1.5, 2];
        let idx = speeds.indexOf(svgSpeed);
        svgSpeed = speeds[(idx + 1) % speeds.length];
        document.getElementById('speedBtn').textContent = `${svgSpeed}x Speed`;
    }

    // Bind new player events
    document.getElementById('playPauseBtn').addEventListener('click', togglePlayPause);
    document.getElementById('stepBtn').addEventListener('click', stepStroke);
    document.getElementById('speedBtn').addEventListener('click', changeSpeed);


function replayImage(item){ initSvgPlayer(item); return;
      writerFallback.hidden = true;
      strokeImg.hidden = false;
      strokeImg.onerror = () => showFallbackWriter(item);
      strokeImg.src = animationUrl(item.k) + `?v=${Date.now()}`;
    }
    function showFallbackWriter(item){
      strokeImg.hidden = true;
      writerFallback.hidden = false;
      writerFallback.innerHTML = '';
      if (!window.HanziWriter) {
        writerFallback.innerHTML = `<div class="jp" style="font-size:140px;font-weight:900;color:#fff;display:grid;place-items:center;width:100%;height:100%">${item.k}</div>`;
        return;
      }
      writer = HanziWriter.create('writerFallback', item.k, {width:250,height:250,padding:12,showCharacter:false,strokeAnimationSpeed:1.35,delayBetweenStrokes:140,strokeColor:'#34d399',radicalColor:'#58a6ff',outlineColor:'rgba(255,255,255,.16)',drawingColor:'#36d6d6'});
      writer.animateCharacter();
    }
    function renderExamples(item){
      $('#examples').innerHTML = item.examples.map(ex => `<div class="ex"><div><b class="jp">${ex.w}</b><span class="jp">${ex.r}</span></div><em>${ex.m}</em></div>`).join('');
    }
    function openModal(item){
      activeItem = item;
      $('#miniKanji').textContent = item.k;
      $('#modalTitle').textContent = `Kanji ${item.k}`;
      $('#modalSub').textContent = `${item.group} · ${item.strokes} goresan`;
      $('#meaningText').textContent = item.meaning;
      $('#onText').textContent = item.on || '-';
      $('#kunText').textContent = item.kun || '-';
      $('#usageText').textContent = item.usage;
      renderExamples(item);

      if (item.sentence) {
          document.getElementById('sentenceJp').textContent = item.sentence.jp;
          document.getElementById('sentenceKana').textContent = item.sentence.kana;
          document.getElementById('sentenceRomaji').textContent = item.sentence.romaji;
          document.getElementById('sentenceMeaning').textContent = item.sentence.meaning;
      } else {
          document.getElementById('sentenceJp').textContent = "";
          document.getElementById('sentenceKana').textContent = "";
          document.getElementById('sentenceRomaji').textContent = "";
          document.getElementById('sentenceMeaning').textContent = "";
      }

      replayImage(item);
      modal.classList.add('show');
      modal.setAttribute('aria-hidden','false');
      document.body.style.overflow = 'hidden';
    }
    function closeModal(){ clearInterval(svgAnimTimer);
      modal.classList.remove('show');
      modal.setAttribute('aria-hidden','true');
      document.body.style.overflow = '';
      if (writer && writer.cancelAnimations) writer.cancelAnimations();
    }
    function speakExample(){
      if (!('speechSynthesis' in window)) return;
      const text = activeItem?.examples?.[0]?.w || activeItem?.k || '';
      speechSynthesis.cancel();
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'ja-JP';
      utterance.rate = .82;
      speechSynthesis.speak(utterance);
    }

    // QUIZ LOGIC & PRACTICE HUB
    const kqModal = $('#kanjiQuizModal');
    const kqBody = $('#kanjiQuizBody');

    // Progress Storage Key
    const KANJI_PROGRESS_KEY = 'gy_jp_kanji_progress_v1';
    let userProgress = {
      learned: {},
      attempts: {},
      correct: {},
      gameStats: {
        meaningQuiz: { played: 0, correct: 0, wrong: 0 },
        readingQuiz: { played: 0, correct: 0, wrong: 0 },
        strokeOrder: { played: 0, correct: 0, wrong: 0 },
        memoryCard: { played: 0, bestTime: null },
        speed60: { played: 0, bestScore: 0 },
        normalQuiz: { played: 0, bestScore: 0 }
      }
    };
    try {
        const stored = localStorage.getItem(KANJI_PROGRESS_KEY);
        if (stored) {
            userProgress = JSON.parse(stored);
        }
    } catch(e) {}

    function saveProgress() {
        localStorage.setItem(KANJI_PROGRESS_KEY, JSON.stringify(userProgress));
    }

    function recordAnswer(kanji, isCorrect) {
        if(!userProgress.attempts[kanji]) userProgress.attempts[kanji] = 0;
        if(!userProgress.correct[kanji]) userProgress.correct[kanji] = 0;
        userProgress.attempts[kanji]++;
        if (isCorrect) {
            userProgress.correct[kanji]++;
            userProgress.learned[kanji] = true;
        }
        saveProgress();
    }

    $('#startKanjiQuizBtn').addEventListener('click', () => {
      kqModal.classList.add('show');
      kqModal.setAttribute('aria-hidden', 'false');
      document.body.style.overflow = 'hidden';
      renderKanjiHub();
    });

    $('#closeKanjiQuizBtn').addEventListener('click', () => {
      kqModal.classList.remove('show');
      kqModal.setAttribute('aria-hidden', 'true');
      document.body.style.overflow = '';
      clearInterval(speedTimer);
    });

    function shuffleArr(array) {
      let cur = array.length, ran;
      while (cur != 0) {
        ran = Math.floor(Math.random() * cur); cur--;
        [array[cur], array[ran]] = [array[ran], array[cur]];
      }
      return array;
    }

    function renderKanjiHub() {
        clearInterval(speedTimer);
        const html = `
            <h2 style="font-size: 28px; margin-bottom: 16px;">Kanji Practice Hub</h2>
            <p style="color: var(--muted); margin-bottom: 24px;">Pilih mode latihan untuk mengasah kemampuan kanjimu.</p>
            <div style="display:grid; grid-template-columns:1fr 1fr; gap:12px; text-align:left;">
                <button class="card" onclick="startMode('tebakArti')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">🎯 Tebak Arti</div><div style="font-size:12px;color:var(--muted)">Tebak arti bahasa Indonesia dari kanji</div></button>
                <button class="card" onclick="startMode('tebakBacaan')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">🗣️ Tebak Bacaan</div><div style="font-size:12px;color:var(--muted)">Pilih Onyomi / Kunyomi yang tepat</div></button>
                <button class="card" onclick="startMode('susunStroke')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">✍️ Susun Stroke</div><div style="font-size:12px;color:var(--muted)">Urutkan goresan kanji dengan benar</div></button>
                <button class="card" onclick="startMode('memoryCard')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">🎴 Memory Card</div><div style="font-size:12px;color:var(--muted)">Cocokkan kanji dengan artinya</div></button>
                <button class="card" onclick="startMode('speed60')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">⏱️ Quiz 60 Detik</div><div style="font-size:12px;color:var(--muted)">Jawab sebanyak-banyaknya dalam 60 detik</div></button>
                <button class="card" onclick="startMode('quizBiasa')"><div style="font-size:18px;font-weight:bold;margin-bottom:4px">📝 Quiz Biasa</div><div style="font-size:12px;color:var(--muted)">10 soal campuran (Format Ujian)</div></button>
            </div>
        `;
        kqBody.innerHTML = html;
    }

    window.startMode = function(mode) {
        if(mode === 'tebakArti') startTebakArti();
        if(mode === 'tebakBacaan') startTebakBacaan();
        if(mode === 'susunStroke') startSusunStroke();
        if(mode === 'memoryCard') startMemoryCard();
        if(mode === 'speed60') startSpeed60();
        if(mode === 'quizBiasa') startQuizBiasa();
    };

    // --- Mode 1: Tebak Arti ---
    let qTotal = 5; let qCur = 0; let qScore = 0; let qPool = [];
    function startTebakArti() {
        userProgress.gameStats.meaningQuiz.played++;
        saveProgress();
        qPool = shuffleArr([...KANJI]).slice(0, 5);
        qCur = 0; qScore = 0;
        renderTebakArti();
    }
    function renderTebakArti() {
        if (qCur >= qPool.length) {
            kqBody.innerHTML = `<h2 style="font-size:32px;margin-bottom:16px;">Selesai!</h2><p>Skor: ${qScore} / 5</p><button class="btn" onclick="renderKanjiHub()">Kembali ke Hub</button>`;
            return;
        }
        let item = qPool[qCur];
        let opts = shuffleArr([item.meaning, ...shuffleArr(KANJI.filter(k=>k.k!==item.k).map(k=>k.meaning)).slice(0,3)]);

        let html = `
            <div style="font-size: 14px; color: var(--amber); font-weight: 700; margin-bottom: 16px;">TEBAK ARTI - ${qCur+1}/5</div>
            <div class="jp" style="font-size: 80px; font-weight: 900; margin-bottom: 16px;">${item.k}</div>
            <div style="font-size: 18px; margin-bottom: 24px;">Apa arti kanji ini?</div>
            <div style="display: grid; gap: 12px; text-align:left;" id="kqOpts">
        `;
        opts.forEach((opt, idx) => { html += `<button class="filter" style="padding:16px 20px; font-size:16px; border-radius:16px;" data-val="${opt}">${opt}</button>`; });
        html += `</div><div id="feedbackBox" style="margin-top:20px;min-height:40px;"></div>`;
        kqBody.innerHTML = html;

        let answered = false;
        document.querySelectorAll('#kqOpts button').forEach(btn => {
            btn.addEventListener('click', function() {
                if(answered) return;
                answered = true;
                let val = this.getAttribute('data-val');
                let isCorr = (val === item.meaning);
                recordAnswer(item.k, isCorr);

                if(isCorr) {
                    this.style.background = 'rgba(16, 185, 129, 0.2)'; this.style.borderColor = '#10b981'; this.style.color = '#34d399';
                    qScore++;
                    userProgress.gameStats.meaningQuiz.correct++;
                } else {
                    this.style.background = 'rgba(239, 68, 68, 0.2)'; this.style.borderColor = '#ef4444'; this.style.color = '#f87171';
                    userProgress.gameStats.meaningQuiz.wrong++;
                }
                saveProgress();

                document.getElementById('feedbackBox').innerHTML = `
                    ${isCorr ? '<div style="color:#34d399;font-weight:bold;margin-bottom:8px">Benar!</div>' : `<div style="color:#f87171;font-weight:bold;margin-bottom:8px">Salah. Jawaban benar: ${item.meaning}</div>`}
                    <div style="font-size:14px;color:var(--muted)">Contoh: ${item.examples[0] ? `${item.examples[0].w} (${item.examples[0].m})` : ''}</div>
                `;
                setTimeout(() => { qCur++; renderTebakArti(); }, 2000);
            });
        });
    }

    // --- Mode 2: Tebak Bacaan ---
    function startTebakBacaan() {
        userProgress.gameStats.readingQuiz.played++;
        saveProgress();
        qPool = shuffleArr([...KANJI]).slice(0, 5);
        qCur = 0; qScore = 0;
        renderTebakBacaan();
    }
    function renderTebakBacaan() {
        if (qCur >= qPool.length) {
            kqBody.innerHTML = `<h2 style="font-size:32px;margin-bottom:16px;">Selesai!</h2><p>Skor: ${qScore} / 5</p><button class="btn" onclick="renderKanjiHub()">Kembali ke Hub</button>`;
            return;
        }
        let item = qPool[qCur];
        let on = item.on ? item.on.split(',')[0].trim() : '';
        let kun = item.kun ? item.kun.split(',')[0].trim() : '';
        let ans = on || kun || 'Tidak ada';

        let opts = shuffleArr([ans, ...shuffleArr(KANJI.filter(k=>k.k!==item.k && (k.on||k.kun)).map(k=> k.on ? k.on.split(',')[0].trim() : k.kun.split(',')[0].trim())).slice(0,3)]);

        let html = `
            <div style="font-size: 14px; color: var(--amber); font-weight: 700; margin-bottom: 16px;">TEBAK BACAAN - ${qCur+1}/5</div>
            <div class="jp" style="font-size: 80px; font-weight: 900; margin-bottom: 16px;">${item.k}</div>
            <div style="font-size: 18px; margin-bottom: 24px;">Apa bacaan Onyomi/Kunyomi utama kanji ini?</div>
            <div style="display: grid; gap: 12px; text-align:left;" id="kqOpts">
        `;
        opts.forEach((opt) => { html += `<button class="filter jp" style="padding:16px 20px; font-size:18px; border-radius:16px;" data-val="${opt}">${opt}</button>`; });
        html += `</div><div id="feedbackBox" style="margin-top:20px;min-height:60px;"></div>`;
        kqBody.innerHTML = html;

        let answered = false;
        document.querySelectorAll('#kqOpts button').forEach(btn => {
            btn.addEventListener('click', function() {
                if(answered) return;
                answered = true;
                let val = this.getAttribute('data-val');
                let isCorr = (val === ans);
                recordAnswer(item.k, isCorr);

                if(isCorr) {
                    this.style.background = 'rgba(16, 185, 129, 0.2)'; this.style.borderColor = '#10b981'; this.style.color = '#34d399';
                    qScore++; userProgress.gameStats.readingQuiz.correct++;
                } else {
                    this.style.background = 'rgba(239, 68, 68, 0.2)'; this.style.borderColor = '#ef4444'; this.style.color = '#f87171';
                    userProgress.gameStats.readingQuiz.wrong++;
                }
                saveProgress();

                document.getElementById('feedbackBox').innerHTML = `
                    ${isCorr ? '<div style="color:#34d399;font-weight:bold;margin-bottom:8px">Benar!</div>' : '<div style="color:#f87171;font-weight:bold;margin-bottom:8px">Salah.</div>'}
                    <div style="font-size:14px;color:var(--muted)">Onyomi: ${item.on||'-'} | Kunyomi: ${item.kun||'-'}</div>
                `;
                setTimeout(() => { qCur++; renderTebakBacaan(); }, 2500);
            });
        });
    }

    // --- Mode 3: Susun Stroke Order ---
    let soItem = null;
    let soSeq = [];
    let soExpected = [];
    function startSusunStroke() {
        userProgress.gameStats.strokeOrder.played++;
        saveProgress();
        // filter kanji that have SVG paths in SVG_DATA
        let validKanji = KANJI.filter(k => SVG_DATA[k.k] && SVG_DATA[k.k].length > 1 && SVG_DATA[k.k].length <= 8);
        if(validKanji.length === 0) validKanji = KANJI;
        soItem = validKanji[Math.floor(Math.random() * validKanji.length)];
        let strokesCount = SVG_DATA[soItem.k] ? SVG_DATA[soItem.k].length : soItem.strokes;

        soExpected = [];
        for(let i=1; i<=strokesCount; i++) soExpected.push(i);
        let shuffled = shuffleArr([...soExpected]);

        soSeq = [];
        let html = `
            <div style="font-size: 14px; color: var(--amber); font-weight: 700; margin-bottom: 16px;">SUSUN STROKE ORDER</div>
            <div class="jp" style="font-size: 60px; font-weight: 900; margin-bottom: 8px;">${soItem.k}</div>
            <div style="font-size: 14px; color:var(--muted); margin-bottom: 24px;">Jumlah goresan: ${strokesCount}. Susun urutan angkanya dengan benar!</div>
            <div style="margin-bottom:20px; font-size:24px; font-weight:bold; min-height:40px; color:var(--cyan)" id="soDisplay"></div>
            <div style="display:flex; flex-wrap:wrap; gap:8px; justify-content:center;" id="soOpts">
        `;
        shuffled.forEach(n => {
            html += `<button class="btn ghost" style="width:50px;height:50px;font-size:20px" onclick="pickSo(${n}, this)">${n}</button>`;
        });
        html += `</div>
            <div id="feedbackBox" style="margin-top:20px;min-height:40px;"></div>
            <div style="margin-top:20px"><button class="btn" onclick="renderKanjiHub()">Batal</button></div>
        `;
        kqBody.innerHTML = html;
    }
    window.pickSo = function(n, btn) {
        soSeq.push(n);
        btn.disabled = true;
        btn.style.opacity = '0.3';
        document.getElementById('soDisplay').textContent = soSeq.join(' → ');

        if (soSeq.length === soExpected.length) {
            let isCorr = soSeq.join(',') === soExpected.join(',');
            recordAnswer(soItem.k, isCorr);
            if(isCorr) {
                userProgress.gameStats.strokeOrder.correct++;
                document.getElementById('feedbackBox').innerHTML = '<div style="color:#34d399;font-weight:bold;font-size:18px">Urutan stroke benar!</div>';
            } else {
                userProgress.gameStats.strokeOrder.wrong++;
                document.getElementById('feedbackBox').innerHTML = `<div style="color:#f87171;font-weight:bold;font-size:18px">Urutan belum tepat.</div><div style="color:var(--muted)">Urutan benar: ${soExpected.join(' → ')}</div>`;
            }
            saveProgress();
            setTimeout(() => { startSusunStroke(); }, 2500);
        }
    }

    // --- Mode 4: Memory Card ---
    let mcCards = [];
    let mcFlipped = [];
    let mcMatched = 0;
    let mcStartTime = 0;
    function startMemoryCard() {
        userProgress.gameStats.memoryCard.played++;
        saveProgress();
        let pool = shuffleArr([...KANJI]).slice(0, 4); // 4 pairs = 8 cards
        mcCards = [];
        pool.forEach(item => {
            mcCards.push({ id: item.k, type: 'kanji', text: item.k });
            mcCards.push({ id: item.k, type: 'meaning', text: item.meaning });
        });
        mcCards = shuffleArr(mcCards);
        mcFlipped = [];
        mcMatched = 0;
        mcStartTime = Date.now();
        renderMemoryCard();
    }
    function renderMemoryCard() {
        let html = `
            <div style="font-size: 14px; color: var(--amber); font-weight: 700; margin-bottom: 16px;">MEMORY CARD KANJI</div>
            <p style="color:var(--muted); margin-bottom:20px">Cocokkan kanji dengan artinya!</p>
            <div style="display:grid; grid-template-columns:repeat(4, 1fr); gap:12px; max-width:400px; margin:0 auto;" id="mcGrid">
        `;
        mcCards.forEach((c, idx) => {
            html += `<div class="mc-card" data-idx="${idx}" style="aspect-ratio:1; border:1px solid var(--line); border-radius:12px; background:rgba(255,255,255,0.05); display:grid; place-items:center; font-size:18px; font-weight:bold; cursor:pointer; user-select:none; transition:0.3s;" onclick="flipMc(${idx}, this)">
                <span style="opacity:0" class="mc-text jp">${c.text}</span>
            </div>`;
        });
        html += `</div><div style="margin-top:30px"><button class="btn" onclick="renderKanjiHub()">Kembali ke Hub</button></div>`;
        kqBody.innerHTML = html;
    }
    window.flipMc = function(idx, el) {
        if(mcFlipped.length >= 2) return;
        if(el.classList.contains('flipped') || el.classList.contains('matched')) return;

        el.classList.add('flipped');
        el.style.background = 'rgba(255,255,255,0.15)';
        el.querySelector('span').style.opacity = '1';
        mcFlipped.push({ idx, el, data: mcCards[idx] });

        if(mcFlipped.length === 2) {
            setTimeout(checkMcMatch, 800);
        }
    }
    function checkMcMatch() {
        let [c1, c2] = mcFlipped;
        if(c1.data.id === c2.data.id && c1.data.type !== c2.data.type) {
            c1.el.classList.add('matched'); c1.el.style.background = 'rgba(16, 185, 129, 0.2)'; c1.el.style.borderColor = '#10b981';
            c2.el.classList.add('matched'); c2.el.style.background = 'rgba(16, 185, 129, 0.2)'; c2.el.style.borderColor = '#10b981';
            mcMatched += 2;
            if(mcMatched === mcCards.length) {
                let timeSpent = Math.floor((Date.now() - mcStartTime) / 1000);
                if (!userProgress.gameStats.memoryCard.bestTime || timeSpent < userProgress.gameStats.memoryCard.bestTime) {
                    userProgress.gameStats.memoryCard.bestTime = timeSpent;
                    saveProgress();
                }
                kqBody.innerHTML = `<h2 style="font-size:32px;margin-bottom:16px;">Selesai!</h2><p>Waktu: ${timeSpent} detik</p><button class="btn" onclick="renderKanjiHub()">Kembali ke Hub</button>`;
            }
        } else {
            c1.el.classList.remove('flipped'); c1.el.style.background = 'rgba(255,255,255,0.05)'; c1.el.querySelector('span').style.opacity = '0';
            c2.el.classList.remove('flipped'); c2.el.style.background = 'rgba(255,255,255,0.05)'; c2.el.querySelector('span').style.opacity = '0';
        }
        mcFlipped = [];
    }

    // --- Mode 5: Quiz Cepat 60 Detik ---
    let speedTimer = null;
    let speedTimeLeft = 60;
    let speedScore = 0;
    let speedWrong = 0;
    function startSpeed60() {
        userProgress.gameStats.speed60.played++;
        saveProgress();
        speedTimeLeft = 60;
        speedScore = 0;
        speedWrong = 0;
        speedTimer = setInterval(() => {
            speedTimeLeft--;
            let el = document.getElementById('speedTimeEl');
            if(el) el.textContent = speedTimeLeft;
            if(speedTimeLeft <= 0) endSpeed60();
        }, 1000);
        nextSpeedQ();
    }
    function nextSpeedQ() {
        let type = Math.random();
        let item = KANJI[Math.floor(Math.random() * KANJI.length)];
        let q, a, opts;

        if (type < 0.5) {
            q = `<div class="jp" style="font-size: 60px; font-weight: 900;">${item.k}</div><div style="font-size:16px">Apa artinya?</div>`;
            a = item.meaning;
            opts = shuffleArr([a, ...shuffleArr(KANJI.filter(k=>k.k!==item.k).map(k=>k.meaning)).slice(0,3)]);
        } else {
            q = `<div style="font-size: 32px; font-weight: bold; color:var(--amber)">${item.meaning}</div><div style="font-size:16px;margin-top:10px">Mana kanjinya?</div>`;
            a = item.k;
            opts = shuffleArr([a, ...shuffleArr(KANJI.filter(k=>k.k!==item.k).map(k=>k.k)).slice(0,3)]);
        }

        let html = `
            <div style="display:flex; justify-content:space-between; margin-bottom:16px; font-size:18px; font-weight:bold;">
                <div style="color:var(--amber)">⏱️ <span id="speedTimeEl">${speedTimeLeft}</span>s</div>
                <div style="color:#34d399">Skor: ${speedScore}</div>
            </div>
            <div style="margin-bottom: 24px; min-height:100px;">${q}</div>
            <div style="display: grid; grid-template-columns:1fr 1fr; gap: 12px; text-align:center;" id="kqOpts">
        `;
        opts.forEach((opt) => { html += `<button class="filter jp" style="padding:20px 10px; font-size:20px; border-radius:16px;" data-val="${opt}">${opt}</button>`; });
        html += `</div>`;
        kqBody.innerHTML = html;

        let answered = false;
        document.querySelectorAll('#kqOpts button').forEach(btn => {
            btn.addEventListener('click', function() {
                if(answered) return;
                answered = true;
                let val = this.getAttribute('data-val');
                if(val === a) {
                    speedScore++;
                    this.style.background = 'rgba(16, 185, 129, 0.2)'; this.style.borderColor = '#10b981';
                } else {
                    speedWrong++;
                    this.style.background = 'rgba(239, 68, 68, 0.2)'; this.style.borderColor = '#ef4444';
                }
                setTimeout(nextSpeedQ, 300);
            });
        });
    }
    function endSpeed60() {
        clearInterval(speedTimer);
        if(speedScore > userProgress.gameStats.speed60.bestScore) {
            userProgress.gameStats.speed60.bestScore = speedScore;
            saveProgress();
        }
        kqBody.innerHTML = `<h2 style="font-size:32px;margin-bottom:16px;">Waktu Habis!</h2>
            <p style="font-size:18px">Skor Akhir: <strong style="color:#34d399">${speedScore}</strong></p>
            <p style="font-size:14px;color:var(--muted);margin-bottom:24px">Salah: ${speedWrong} | Best Score: ${userProgress.gameStats.speed60.bestScore}</p>
            <button class="btn" onclick="renderKanjiHub()">Kembali ke Hub</button>`;
    }

    // --- Mode 6: Quiz Biasa (The original logic wrapped) ---
    const trapPairs = [
      {k1: '大', k2: '太', m1: 'besar', m2: 'gemuk'},
      {k1: '土', k2: '士', m1: 'tanah', m2: 'prajurit'},
      {k1: '人', k2: '入', m1: 'orang', m2: 'masuk'},
      {k1: '木', k2: '本', m1: 'pohon', m2: 'buku'},
      {k1: '日', k2: '白', m1: 'hari', m2: 'putih'},
      {k1: '千', k2: '干', m1: 'seribu', m2: 'kering'},
      {k1: '万', k2: '方', m1: 'sepuluh ribu', m2: 'arah'}
    ];
    let kqQuestions = []; let kqCurrent = 0; let kqScore = 0; let kqMistakes = [];
    function startQuizBiasa() {
        userProgress.gameStats.normalQuiz.played++;
        saveProgress();
        const pool = shuffleArr([...KANJI]);
        kqQuestions = []; kqCurrent = 0; kqScore = 0; kqMistakes = [];

        for(let i=0; i<10; i++) {
            let type = Math.random();
            let q, a, wrongMap;
            let item = pool[i];

            if(i === 2 || i === 7) {
                let trap = trapPairs[Math.floor(Math.random() * trapPairs.length)];
                let isK1 = Math.random() > 0.5;
                let targetK = isK1 ? trap.k1 : trap.k2;
                let targetM = isK1 ? trap.m1 : trap.m2;
                let wrongM = isK1 ? trap.m2 : trap.m1;
                q = `Apa arti dari kanji <span class="jp" style="font-size:32px;color:var(--amber)">${targetK}</span> ?`;
                a = targetM;
                let others = shuffleArr(KANJI.filter(x => x.meaning !== targetM && x.meaning !== wrongM)).slice(0, 2).map(x=>x.meaning);
                kqQuestions.push({ q, a, opts: shuffleArr([a, wrongM, ...others]) });
                continue;
            }

            if(i === 4 || i === 8) {
                if(item.examples.length > 0) {
                    let ex = item.examples[0];
                    q = `Dalam kata <span class="jp" style="font-size:24px;color:var(--amber)">${ex.w}</span>, bagaimana cara membacanya?`;
                    a = ex.r;
                    let others = shuffleArr(KANJI.flatMap(x=>x.examples).map(x=>x.r).filter(x=>x!==a)).slice(0,3);
                    kqQuestions.push({ q, a, opts: shuffleArr([a, ...others]) });
                    continue;
                }
            }

            if (type < 0.4) {
              q = `Apa arti dari <span class="jp" style="font-size:32px;color:var(--amber)">${item.k}</span> ?`;
              a = item.meaning;
              wrongMap = shuffleArr(KANJI.filter(x => x.k !== item.k).map(x => x.meaning)).slice(0,3);
            } else if (type < 0.7) {
              q = `Manakah yang termasuk Onyomi dari <span class="jp" style="font-size:32px;color:var(--amber)">${item.k}</span> ?`;
              a = item.on ? item.on.split(',')[0].trim() : (item.kun ? item.kun.split(',')[0].trim() : 'Tidak ada');
              wrongMap = shuffleArr(KANJI.filter(x => x.k !== item.k && x.on).map(x => x.on.split(',')[0].trim())).slice(0,3);
            } else {
              q = `Manakah yang termasuk Kunyomi dari <span class="jp" style="font-size:32px;color:var(--amber)">${item.k}</span> ?`;
              a = item.kun ? item.kun.split(',')[0].trim() : (item.on ? item.on.split(',')[0].trim() : 'Tidak ada');
              wrongMap = shuffleArr(KANJI.filter(x => x.k !== item.k && x.kun).map(x => x.kun.split(',')[0].trim())).slice(0,3);
            }
            kqQuestions.push({ q, a, opts: shuffleArr([a, ...wrongMap]) });
        }
        renderQuizBiasaQ();
    }
    function renderQuizBiasaQ() {
      if(kqCurrent >= kqQuestions.length) {
        finishQuizBiasa();
        return;
      }
      let q = kqQuestions[kqCurrent];

      let html = `
        <div style="font-size: 14px; color: var(--amber); font-weight: 700; margin-bottom: 16px; text-transform: uppercase;">QUIZ BIASA - Soal ${kqCurrent + 1} / 10</div>
        <div style="font-size: 24px; font-weight: 800; margin-bottom: 32px; line-height: 1.4;">${q.q}</div>
        <div style="display: grid; gap: 12px; text-align:left;" id="kqOpts">
      `;
      q.opts.forEach((opt, idx) => {
          html += `<button class="filter" style="padding:16px 20px; font-size:16px; border-radius:16px;" data-idx="${idx}">${opt}</button>`;
      });
      html += `</div>`;
      kqBody.innerHTML = html;

      let answered = false;
      document.querySelectorAll('#kqOpts button').forEach(btn => {
          btn.addEventListener('click', function() {
              if(answered) return;
              answered = true;
              let opt = this.textContent;
              if(opt === q.a) {
                  this.style.background = 'rgba(16, 185, 129, 0.2)'; this.style.borderColor = '#10b981'; this.style.color = '#34d399';
                  kqScore++;
              } else {
                  this.style.background = 'rgba(239, 68, 68, 0.2)'; this.style.borderColor = '#ef4444'; this.style.color = '#f87171';
                  kqMistakes.push({q: q.q, a: q.a, u: opt});
                  document.querySelectorAll('#kqOpts button').forEach(b => {
                      if(b.textContent === q.a) { b.style.borderColor = '#10b981'; b.style.color = '#34d399'; }
                  });
              }
              setTimeout(() => { kqCurrent++; renderQuizBiasaQ(); }, 1000);
          });
      });
    }

    function finishQuizBiasa() {
        if(kqScore > userProgress.gameStats.normalQuiz.bestScore) {
            userProgress.gameStats.normalQuiz.bestScore = kqScore;
            saveProgress();
        }
      let msg = "";
      if(kqScore >= 9) msg = "Luar biasa! Pemahaman Kanji N5 Anda sangat tajam.";
      else if(kqScore >= 7) msg = "Bagus sekali! Perhatikan jebakan kanji yang mirip.";
      else if(kqScore >= 5) msg = "Cukup baik. Perbanyak latihan membaca kalimat.";
      else msg = "Terus berlatih! Ulangi hafalan arti dan onyomi/kunyomi dasar.";

      let html = `
        <div style="font-size: 16px; color: var(--amber); font-weight: 700; margin-bottom: 8px;">HASIL TEST</div>
        <div style="font-size: 72px; font-weight: 900; color: var(--amber); line-height: 1; margin-bottom: 8px;">${kqScore}/10</div>
        <div style="font-size: 18px; margin-bottom: 32px; color: var(--muted);">${msg}</div>
      `;

      if(kqMistakes.length > 0) {
          html += `<div style="text-align: left; background: rgba(255,255,255,0.03); border-radius: 16px; padding: 20px; border: 1px solid var(--line); margin-bottom: 32px; max-height:200px; overflow-y:auto;">
            <div style="font-weight: bold; margin-bottom: 16px;">Review Kesalahan:</div>
          `;
          kqMistakes.forEach(m => {
             html += `
                <div style="border-bottom: 1px solid var(--line); padding-bottom: 12px; margin-bottom: 12px;">
                  <div style="font-size: 14px; color: var(--muted); margin-bottom: 4px;">${m.q}</div>
                  <span style="font-size: 16px; font-weight: bold; color: #10b981;">${m.a}</span>
                  <span style="font-size: 14px; color: #ef4444; text-decoration: line-through; margin-left: 8px;">${m.u}</span>
                </div>
             `;
          });
          html += `</div>`;
      }

      html += `<button class="btn" onclick="renderKanjiHub()" style="padding: 16px 32px; font-size: 16px; width:100%;">Kembali ke Hub</button>`;
      kqBody.innerHTML = html;
    }

    //
    searchInput.addEventListener('input', e => { query = normalize(e.target.value); render(); });
    $('#closeBtn').addEventListener('click', closeModal);
    $('#shade').addEventListener('click', closeModal);
    $('#replayBtn').addEventListener('click', () => replayImage(activeItem));
    $('#soundBtn').addEventListener('click', speakExample);
    document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });
    render();
  </script>
  <script src="assets/js/partikel.utils.js"></script>
  <script src="assets/js/game-engine.js"></script>
  <script src="assets/js/kanji.game.js"></script>
  <script>document.addEventListener('DOMContentLoaded', function() { lucide.createIcons(); });</script>
</body>
</html>
